INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, useful_count, review_count, quality_score, categories, category1, category2, category3) VALUES 
('68028374e3c98b094176605a', '谢谢酒店免费给我升到行政房，会再次入住！', '["https://dimg04.c-ctrip.com/images/0236t224x8tjz9840DD67_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235p224x8tjz81sm12A3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-12-13', '花园大床房', '大床房', '情侣出游', 20, 0, 2, 4, '["整体满意度","前台服务"]'::jsonb, '整体满意度', '前台服务', NULL),
('68028374e3c98b094176605b', '到处都是花的花园酒店，到步登记入住便送上两支鲜花??！
太太指定再要入住的星级酒店！', '["https://dimg04.c-ctrip.com/images/0234j2224wxbtutv437B7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236m2224wxbtv9aoF28D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233q2215gtynspup4CC5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235j2234d0ozynlsEC1E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-28', '花园大床房', '大床房', '家庭亲子', 42, 0, 11, 6, '["整体满意度","前台服务"]'::jsonb, '整体满意度', '前台服务', NULL),
('68028385e3c98b094176605c', '房间漂亮、舒适、床比较软，冷气好够凉，洗澡热水够热。地点方便，有地铁淘金站一出就到。自助早餐多种可选，味道唔错。', '["https://dimg04.c-ctrip.com/images/0235h12000c8gicra7656_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235k12000c8g4otuE0D8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230412000c8ge979D88C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235l12000c8gd8pq5D0B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-25', '花园大床房', '大床房', '家庭亲子', 56, 0, 3, 7, '["房间设施","交通便利性","餐饮设施"]'::jsonb, '房间设施', '交通便利性', '餐饮设施'),
('68028385e3c98b094176605d', '20年没来广州了 第一次住招待所 自助餐就是让人更加雪上加霜 太糟糕了  200元的早餐 我只能选一碗白粥。

太差了  太差了', '["https://dimg04.c-ctrip.com/images/0232s12000c30pc3t5657_R_150_150_R5_Q70_D.jpg"]'::jsonb, 1, 1, '2023-09-07', '花园双床房', '双床房', '商务出差', 64, 0, 18, 4, '["餐饮设施","性价比","整体满意度"]'::jsonb, '餐饮设施', '性价比', '整体满意度'),
('68028385e3c98b094176605e', '服务良好，设备高级，可惜入住当次房间打扫不确实（双床之间走道有点脏），床上被子里遗落一坨头发。厕所跟卫浴门用滑门共用挺特别的。', '["https://dimg04.c-ctrip.com/images/0236b2224wh2k8qq87026_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234h2215gdpe67a8EA9B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2023-09-17', '花园大床房', '大床房', '商务出差', 63, 0, 552, 7, '["客房服务","房间设施","卫生状况"]'::jsonb, '客房服务', '房间设施', '卫生状况'),
('68028385e3c98b094176605f', '我在1922号房间，碰巧冷气空调漏水。酒店帮我换房到1388商务房。安排快捷。

退房有服务员接过我的房咭，简单询问有没有consume 房内food and beverage 便可以离开，不用queue up 长长的人龙。

2楼中式点心餐厅，价格相对高但服务态度良好。我点了牛肉，肠粉及糯米鸡都不俗。', '["https://dimg04.c-ctrip.com/images/0232y2224vo4x4gpc7337_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-07-06', '花园大床房', '大床房', '商务出差', 152, 0, 2, 8, '["退房/入住效率","房间设施","餐饮设施"]'::jsonb, '退房/入住效率', '房间设施', '餐饮设施'),
('68028385e3c98b0941766060', '我们的订单每天有2份早餐，但酒店记录只显示1份。我们必须出示trip.com的确认信息（幸好丈夫已经打印出来了，我们在订单中找不到了），他们检查了他们的记录是错误的。接待处的比利没有微笑，我认为他应该让我多加 1 份早餐（因为提前添加有折扣），但他没有这样做，让我花了半个小时来证明我应该吃 2 份早餐第二天早上。经理 Yannes 已经道歉并让我们在 VIP 休息室吃早餐（下午茶时间和欢乐时光也免费）。食物只是一般。女服务员问我食物还好吗，我说班尼迪克蛋面包太软了。然后她回答说通常人们不吃面包。你觉得她的回答很奇怪吗？
酒店很宏伟，花园和池塘很漂亮，房间很舒适，但你可以听到隔壁房间的噪音。保洁阿姨笑容很好，很有礼貌。
非常靠近地铁站和点豆鸭餐厅。', '["https://dimg04.c-ctrip.com/images/0231012000bktkdy25DC8_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0232p12000bktk2vnBA5D_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0231f12000bktkke4BA55_R_150_150_R5_Q70_D.png"]'::jsonb, 3.5, 3, '2023-07-05', '花园大床房', '大床房', '情侣出游', 327, 0, 1, 8, '["前台服务","餐饮设施","安静程度"]'::jsonb, '前台服务', '餐饮设施', '安静程度'),
('68028385e3c98b0941766061', '邻近地铁站，位置方便。最可惜嘅地方，系附近有工程比较嘈。酒店房间都算新净，舒服。下次会再来的，不错不错', '["https://dimg04.c-ctrip.com/images/0230g12000c4l8zjkC594_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0235f12000c4l8s9a89D8_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0235m12000c4l8zr32FB2_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0232r12000c4l8sfbD908_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0234o12000c4l8pgo06C0_R_150_150_R5_Q70_D.png"]'::jsonb, 4.5, 4, '2023-09-13', '红棉双床套房', '套房', '家庭亲子', 51, 0, 21, 6, '["交通便利性","安静程度","整体满意度"]'::jsonb, '交通便利性', '安静程度', '整体满意度'),
('68028385e3c98b0941766062', '地方比较旧，办理入住要排队15分钟以上，一开始就我一个人在排队。清洁不太好，淋浴间有很多霉菌。我住在 21 楼，外部施工非常吵闹。所以我睡不好觉。', '["https://dimg04.c-ctrip.com/images/0235v12000bqi7qsp9738_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0230a12000bqi7ktg74B8_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0231w12000bqi7twfC7C0_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0230b12000bqi8i1g08FA_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0235z12000bqi8o4f0001_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0234h12000bqi8oic384E_R_150_150_R5_Q70_D.png"]'::jsonb, 1.7, 1, '2023-07-24', '花园大床房', '大床房', '独自旅行', 73, 0, 59, 7, '["卫生状况","安静程度","退房/入住效率"]'::jsonb, '卫生状况', '安静程度', '退房/入住效率'),
('68028385e3c98b0941766063', '酒店服务上选，卫生，设施中上', '["https://dimg04.c-ctrip.com/images/0232g2224x2zu84c044C6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.2, 4, '2023-11-11', '红棉双床套房', '套房', '商务出差', 14, 0, 2, 4, '["整体满意度","卫生状况","房间设施"]'::jsonb, '整体满意度', '卫生状况', '房间设施'),
('68028385e3c98b0941766064', '钴
我从抵达之日起就一直拥有一家非常好的酒店，并且从 bkues li 开始就得到了很好的关注', '["https://dimg04.c-ctrip.com/images/0235e12000c1yxeavE3FF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2023-09-02', '花园大床房', '大床房', '商务出差', 47, 1, 1, 2, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68028385e3c98b0941766065', '服务人员态度差，不礼貌对待客人，住两晚，第二日房卡已经唔可以用，去前台续，工作人员要查这查那？加上现在附近建地铁站比较嘈！一早就嘈，酒店指引不是太清晰！但房间环境还不错！', '["https://dimg04.c-ctrip.com/images/023052224vp15fq4wB278_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/023682224vp15h0fkB0B1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230d2224vp15iaqa7B02_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2023-07-08', '花园大床房', '大床房', '商务出差', 85, 0, 67, 6, '["前台服务","安静程度","整体满意度"]'::jsonb, '前台服务', '安静程度', '整体满意度'),
('68028390e3c98b0941766066', '房间整体环境干净卫生，服务贴心，自助餐丰富，款式多样，本人不舒服酒店管理人员也马上作出妥善调整安排，万分感谢！', '["https://dimg04.c-ctrip.com/images/0231j12000bt5fm1o19C7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230x12000bt593tg7400_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231r12000bt5fvmm41A6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232b12000bt5cdog43ED_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232g12000bt59ovpA047_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230a12000bt55ej20E62_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231112000bt574yd4B3B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235n12000bt5c5498244_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236512000bt5fo8zCC6A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-08-02', '花园大床房', '大床房', '独自旅行', 55, 0, 8, 8, '["卫生状况","前台服务","餐饮设施"]'::jsonb, '卫生状况', '前台服务', '餐饮设施'),
('68028390e3c98b0941766067', '疫情后和丈夫一起陪老父返广州扫墓，选了入住著名的花园酒店两晚，由于需要加床，于是加钱提升了房间至套房，感觉物有所值，房间大以及干净整洁，而且隔音不错，见老父虽然疲倦但晚上仍睡得好，很难得。退房日早上到花园走了一圈，花园设计及打理得很好，鱼池锦鲤处处，生气勃勃；也到了三楼的博物馆走走，博物馆比我想像中规模大，设计也很到位，老父见到珍贵的旧相片也回忆到当年在广州的旧事呢！离开前到米芝连级中菜厅桃园馆享用了一餐值得回味的美食，十分赞！', '["https://dimg04.c-ctrip.com/images/0235q12000awtzg957335_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0235012000awtztv92BAC_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0230t12000awtzbz9AF4B_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0232212000awtzqaoE2E0_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0233612000awv8go9FE67_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0231512000awv82ahDEC6_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0234u12000awv7mdy98CA_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0236712000awv8ena92D5_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0233l12000awv7z9dDFDD_R_150_150_R5_Q70_D.png"]'::jsonb, 5, 5, '2023-04-11', '花园双床房', '双床房', '家庭亲子', 216, 0, 1, 9, '["房间设施","整体满意度","餐饮设施"]'::jsonb, '房间设施', '整体满意度', '餐饮设施'),
('68028390e3c98b0941766068', '很喜欢我的住宿体验', '["https://dimg04.c-ctrip.com/images/0234v4234d5axa3cw895D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/023474234d5axb5xs50AA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-11-08', '花园大床房', '大床房', '独自旅行', 9, 0, 1, 3, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68028390e3c98b0941766069', '入住时，前台Vivia小姐非常亲切的?接待，升等到新装修套房装潢非常精致，期待下次再次入住，祝花园酒店生意兴隆！万事如意??', '["https://dimg04.c-ctrip.com/images/0235u12000bcnlmccC31D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231d12000bcnip3o8EE6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231x12000bcnahriCAF7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232512000bcnjpzm8B6A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233712000bcncfx112AE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235k12000bcnh03zFAE1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235e12000bcni08aBE06_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236212000bcnmw35566B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235u12000bcnmt7t73D0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-06-04', '红棉大床套房', '套房', '情侣出游', 62, 0, 2, 6, '["前台服务","房间设施","整体满意度"]'::jsonb, '前台服务', '房间设施', '整体满意度'),
('68028390e3c98b094176606a', '酒店很大。又旧又脏。我住在高级舒适房，我的同事住在普通房间。虽然房间是禁烟的，但房间里有烟味和灰尘味。酒店本身很破旧。', '["https://dimg04.c-ctrip.com/images/0233s4215flzv6f4w097C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232s4215flzv6muo9774_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235q4234bsq7ckls360F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 2.2, 2, '2023-07-09', '红棉大床套房', '套房', '商务出差', 59, 0, 23, 5, '["卫生状况","房间设施","整体满意度"]'::jsonb, '卫生状况', '房间设施', '整体满意度'),
('68028390e3c98b094176606b', '漂亮干净的客房。很棒的晚餐。', '["https://dimg04.c-ctrip.com/images/0234y2234d4nkv8z49F90_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232c2224x1aesx8w825E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2023-11-07', '花园大床房', '大床房', '商务出差', 14, 0, 12, 3, '["房间设施","餐饮设施","卫生状况"]'::jsonb, '房间设施', '餐饮设施', '卫生状况'),
('68028390e3c98b094176606c', '好似都无乜加价，平咗好多咁，我地原本拣每晚$1100 港币嘅大床普通房，去到check in 酒店帮我地升级去每晚千八蚊港币粤韵大床房，唔须要补差价，服务细心，房间装修新净，地方干净！所有酒店应该备有嘅物品都唔缺少。', '["https://dimg04.c-ctrip.com/images/0234p2215elxgkkxc0E50_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/023462215elxgksn48D94_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233c2224upamnrip6B81_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236i2215elxgl82oB450_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/023332234asnsqy407BD8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/023322234asnsr5ts054E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233i2224upamoeo01B9E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231k2224upamomds76B9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231f2224upamou3kC87A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-04-09', '花园大床房', '大床房', '情侣出游', 108, 0, 12, 8, '["性价比","前台服务","卫生状况"]'::jsonb, '性价比', '前台服务', '卫生状况'),
('68028390e3c98b094176606d', '第一次入住，柜台特别安排中间的房间15楼，虽然旁边有新的地铁站在施工，但入住期间没有被施工噪音影响，连续住了三天非常舒适，非常推荐到广州的旅人可以入住，交通便利。早餐基本的都有，环境干净，吃饱还可以到外面的花园瀑布散步走走景色优美。', '["https://dimg04.c-ctrip.com/images/0233m2234atyllqn45683_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/023522224uqlfj774194D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234w2215en89gnr421A7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234f2215en89h36o3199_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233l2234atylmt80FE11_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235e2224uqlfk9s114E0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/023312215en89hqc1592D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234n2215en89i5rkD686_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-04-13', '花园大床房', '大床房', '家庭亲子', 116, 0, 5, 8, '["整体满意度","交通便利性","安静程度"]'::jsonb, '整体满意度', '交通便利性', '安静程度'),
('68028390e3c98b094176606e', '好怀旧又不失现代感的装修，房间很大很舒适，特别欣赏酒店内的博物馆，里面的收藏真系好有心思，值得下次再来看', '["https://dimg04.c-ctrip.com/images/023742234bborckeoCA45_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-05-27', '花园双床房', '双床房', '家庭亲子', 52, 0, 11, 8, '["整体满意度","房间设施","公共设施"]'::jsonb, '整体满意度', '房间设施', '公共设施'),
('68028390e3c98b094176606f', '房间很舒适，但是床有点太软，而且外面有工程进行中，嘈音很大，不得不要求换房间，幸好最后也安排了。早餐种类可以，但餐厅装修很土。所有的职员都十分有礼，值得再次入住。', '["https://dimg04.c-ctrip.com/images/0231v2215emazidgh861D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230q2215emazidggE67F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233o2234at1bnvs10BC5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/023692224upo5l4m8EA46_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/023592215emazidgi0F9D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232p2215emazil68B1CE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.2, 4, '2023-04-10', '花园大床房', '大床房', '情侣出游', 81, 0, 39, 8, '["安静程度","房间设施","整体满意度"]'::jsonb, '安静程度', '房间设施', '整体满意度'),
('6802839be3c98b0941766070', '一切都很完美，尤其是在柜台的托尼非常非常乐于助人！我们下次肯定会回来??', '["https://dimg04.c-ctrip.com/images/0235x12000bhkilmh6612_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234z12000bhkl1i707B1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231b12000bhkmtbl5519_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-06-24', '花园双床房', '双床房', '朋友出游', 36, 0, 2, 4, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('6802839be3c98b0941766071', '酒店位置十分方便，酒店设施非常完善，房间内环境卫生令人满意，酒店内食肆的质素非常高！服务人态度亦殷勤！值得推荐！', '["https://dimg04.c-ctrip.com/images/0234x2224ux6pn26p1D1F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-04-29', '花园大床房', '大床房', '商务出差', 56, 0, 9, 7, '["交通便利性","整体满意度","餐饮设施"]'::jsonb, '交通便利性', '整体满意度', '餐饮设施'),
('6802839be3c98b0941766072', '大堂很漂亮，有中国新年装饰。
预订细节有误会，但很快就处理了。我认为这是预期的。
有意见说设施老旧，但干净舒适。房间卫生很难维护，所以是一流的酒店。
酒店的早餐是自助式的，一切都很美味。
酒店内的点心餐厅非常好吃，我们只能在这家酒店才能品尝到。脆皮特别好吃。
另外,是想住在的酒店。', '["https://dimg04.c-ctrip.com/images/0234312000ai74302A2E5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232q12000ai72xw20F8E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231412000ai7358c7183_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2023-01-25', '红棉双床套房', '套房', '家庭亲子', 141, 0, 24, 7, '["餐饮设施","整体满意度","卫生状况"]'::jsonb, '餐饮设施', '整体满意度', '卫生状况'),
('6802839be3c98b0941766073', '在广州生活了快30年；第一次入住这个在家门口的老牌酒店，本次作为生日的staycation旅程，总体感觉还是比较满意的，主要想提及一下下面几个方面：
一、服务
1.入住时因为是岭南金卡会员，主动升级了一个小套房和告知有一位行政酒廊礼遇，前台工作的同事也很热情；
2.作为第一次体验行政酒廊的‘大乡里’来说，特别要感谢及点赞酒廊里面的同事Cons小哥哥，服务非常周到，同时因为到达时间已经是happyhour了，Cons还特地来写了一张邀请函，说明天我们退房后还可以来体验下午茶，很贴心??
3.晚上因为胃部不适外卖了药品，因为实在走不动，致电前台希望能有同事帮忙送一下到房间，结果遭到冰冷拒绝，还是需要拖着不舒服的身体到楼下去取，这个是令我的体验感大打折扣的。
二、房间
升级了小套房，比较古色古香岭南风格的设计很舒适，但是希望酒店还能在细节方面再注意一下：
1.床脚其中一个角的床单没有折好，令人感觉有点‘唠搞’
2.客厅的地毯上估计是一些边角位吸尘没有很注意到，有一些饼干屑一样的东西，希望可以注意一下
3.被套上有一小点红色，但是看起来不像血渍故没有让客服去处理
4.放置备品的小架子希望客房人员注意一下彻底的清洁，虽然小抽屉拉出来拉一半看不到，可是牙刷拿出来发现小抽屉靠里面的位置居然残留上一位客人用过的剃须刀外包装纸盒，究竟有没有认真清洁这个我真的要打一个问号了。

总之，此行总体体验感还是很不错的，服务很加分特别是Cons小哥哥真的令我感到像老朋友一样的窝心', '["https://dimg04.c-ctrip.com/images/0234k12000ag3gxk164FA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232912000ag3gtjy6105_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232r12000ag3fuijC0EF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2023-01-15', '花园大床房', '大床房', '情侣出游', 636, 0, 2, 9, '["客房服务","前台服务","卫生状况"]'::jsonb, '客房服务', '前台服务', '卫生状况'),
('6802839be3c98b0941766074', '酒店整体满意，位置方便旁边就是地铁站
住的很满意，Mikey帮忙退房服务很热情周到～
下次还会考虑入住花园酒店', '["https://dimg04.c-ctrip.com/images/0236t12000arku7854AF4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-03-12', '花园大床房', '大床房', '商务出差', 55, 0, 5, 6, '["整体满意度","交通便利性","前台服务"]'::jsonb, '整体满意度', '交通便利性', '前台服务'),
('6802839be3c98b0941766075', '这家酒店非常适合商务和家庭入住，我真的很享受这次住宿。他们在酒店内也有博物馆', '["https://dimg04.c-ctrip.com/images/0232h2234alrhe8vlC2D7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-03-23', '花园双床房', '双床房', '商务出差', 38, 0, 25, 5, '["整体满意度","公共设施"]'::jsonb, '整体满意度', '公共设施', NULL),
('680283a6e3c98b094176607a', '环境幽雅，很舒服', '["https://dimg04.c-ctrip.com/images/0235q12000adacyk9A34D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-03', '红棉大床套房', '套房', '商务出差', 8, 0, 4, 3, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68028542e3c98b0941766084', '非常满意，这个时间，这个价格属于性价比非常高了。而且就在中心附近，出入也非常的方便。尤其是早餐，是目前吃过最满意的', '["https://dimg04.c-ctrip.com/images/0233y12000i6vabd54936_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234g12000i6vsssm55BB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233z12000i6vtpeb447C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-01-31', '花园双床房', '双床房', '商务出差', 57, 0, 193, 7, '["性价比","交通便利性","餐饮设施"]'::jsonb, '性价比', '交通便利性', '餐饮设施'),
('68028542e3c98b0941766085', '房间非常好，设施设备齐全，服务热情周到，酒店的餐饮也非常好。花园酒店有一个博物馆，介绍了酒店的发展历程，非常值得看看。', '["https://dimg04.c-ctrip.com/images/0230812000hjxwfqtD13D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232k12000hjxru8k2486_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232q12000hjym0g7EF0A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231x12000hjy926b88B1_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-01-02', '花园双床房', '双床房', '情侣出游', 59, 0, 53, 7, '["房间设施","餐饮设施","整体满意度"]'::jsonb, '房间设施', '餐饮设施', '整体满意度'),
('68028542e3c98b0941766086', '给领导定的酒店。大堂真的超显气派，不愧是广州第一家五星级酒店，进去就让人感觉与众不同。前台也别具一格，价格小贵，但服务真好！', '["https://dimg04.c-ctrip.com/images/0232512000h1fr74p2E40_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230j12000h1g1sxg07C0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233e12000h1fgv9w24D1_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-12-04', '花园大床房', '大床房', '商务出差', 62, 0, 86, 7, '["前台服务","整体满意度","价格合理性"]'::jsonb, '前台服务', '整体满意度', '价格合理性'),
('68028542e3c98b0941766087', '很不错的。', '["https://dimg04.c-ctrip.com/images/0235r12000hjiugf5230F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231c12000hjim8yiBAC4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233r12000hjiwpwj89C7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-01-02', '花园大床房', '大床房', '朋友出游', 5, 0, 276, 1, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68028542e3c98b0941766089', '这是我第二次入住该酒店了，为什么会选择继续入住呢，因为这里的服务，环境，前台工作人员的热心都让人宾至如归，我记得第一次我们订了5间房，但是不在一个楼层，前台好像叫什么Cookie的漂亮小妹不仅给我们几个朋友协调了同一楼层，还免费升级了，让你记忆深刻。如果下次让我选择我还是会继续选择该酒店入住。', '["https://dimg04.c-ctrip.com/images/0232n12000jb41js08B38_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0232e12000jb41flj89E6_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0232l12000jb42pnsE639_R_150_150_R5_Q70_D.png"]'::jsonb, 5, 5, '2025-03-25', '红棉双床套房', '套房', '朋友出游', 147, 0, 2, 8, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68028542e3c98b094176608a', '出差的好住处，花园酒店虽然有年头了，但是维护很好也很干净，前台，餐厅和客房服务都很不错。
房间比较大和舒适，提供的洗护产品味道很好', '["https://dimg04.c-ctrip.com/images/0231x12000jp4wkbc09C4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231912000jp3t7wn8EBF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235j12000jp5b6a57354_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231e12000jp43xp211EC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233e12000jp4z8znFFB8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-04-10', '花园双床房', '双床房', '商务出差', 65, 0, 77, 7, '["整体满意度","卫生状况","前台服务"]'::jsonb, '整体满意度', '卫生状况', '前台服务'),
('68028542e3c98b094176608b', '房间做了升级，谢谢Rem????，续住的时候不用我去前台排队办手续，帮我把做好的房卡送到房间，谢谢小谢??????，宾至如归具像化，期待下次的相遇??????', '["https://dimg04.c-ctrip.com/images/0231812000jmlh13r2788_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234o12000jmlxudu6D1E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236612000jmkjkh717B1_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-04-07', '红棉大床套房', '套房', '商务出差', 79, 0, 41, 8, '["前台服务","客房服务"]'::jsonb, '前台服务', '客房服务', NULL),
('68028542e3c98b094176608c', '酒店前台YOLO服务好！！酒店各项设施也很不错，入住还有欢迎水果！景观很不错，推荐入住，酒店地理位置特别好，去各个景点都很方便！早餐多選擇，非常好味??', '["https://dimg04.c-ctrip.com/images/0233v224x8zz3fk5g610B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236i224x8zz25ttp2991_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235w224x8zz1y6tp5FE6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-03-18', '花园大床房', '大床房', '家庭亲子', 76, 0, 6, 7, '["前台服务","景观/朝向","交通便利性"]'::jsonb, '前台服务', '景观/朝向', '交通便利性'),
('68028542e3c98b094176608d', '老牌子的酒店，交通方便，旁边就有地铁，车到酒店服务人员帮助拿行李，前台帅小伙帮忙升级一间房间，虽然过程有点慢，但对房间还是非常满意，毕竟过年人多，酒店管理还是挺有序的。早晨的瀑布歺厅早歺挺不错，一边吃饭一边看着瀑布，心情非常好，参观了酒店的博物馆，了解酒店发展史，真的不错，总之游广州住花园酒店是个很好的选择。', '["https://dimg04.c-ctrip.com/images/0235d12000i91ehiuE1E2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230n12000i9173a31B3D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235312000i920h0984AA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230312000i91np9u41BD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-02', '花园双床房', '双床房', '家庭亲子', 155, 0, 54, 8, '["交通便利性","前台服务","餐饮设施"]'::jsonb, '交通便利性', '前台服务', '餐饮设施'),
('68028542e3c98b094176608e', '来广州五天四晚，全住在广州花园酒店，前两天红棉大床房，后两天行程临时改变退了后面的酒店想这边续住只有绿央双床了，酒店所有的服务都很好，入住送了精致的点心，携程钻石关联了金卡赠送了早餐和行政酒廊，行政酒廊有个外国面孔的女孩非常热情，酒店有个博物馆可以进去看看，小花园不大但是打理的不错，红棉大床房我和家人都非常满意，干净宽敞没有异味房间也比较漂亮，但是换到绿央觉得有些糟糕，房间很小，设施陈旧，有霉味，这些我也能理解毕竟老酒店，但是绿央房间的玻璃非常的脏，这个是我理解不了的，酒店窗户开的话需要签免责声明，我不理解为啥不能给装上限位器，一开始住红棉楼层比较高我也没敢开，但是绿央霉味太重孩子进去就老咳嗽，我就叫把窗户打开了，但是就很操心，实际我订房后面绿央比红棉每天还贵600+，红棉推荐，绿央房强烈不推荐。', '["https://dimg04.c-ctrip.com/images/0230b12000i7j121a812E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230312000i7jjtzw978E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231e12000i7j9a58A7DF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235o12000i7ioem70D7C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233d12000i7ip1u5CB76_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-01', '红棉大床套房', '套房', '家庭亲子', 353, 0, 10, 9, '["房间设施","整体满意度","价格合理性"]'::jsonb, '房间设施', '整体满意度', '价格合理性'),
('68028542e3c98b094176608f', '春节期间订了三间房住了四晚，新春南国醒狮很有特色，酒店大堂布置的很好，还有新春手工活动。
房间打扫的是一个尼泊尔小姑娘，虽然语言不通，但是她态度非常好
自助早餐一层，三层，三十层都可以，种类基本上一样
酒店的博物馆很值得参观，孩子参观后还用了相关内容做了寒假作业', '["https://dimg04.c-ctrip.com/images/0231o12000iby9roz1140_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231x12000ibyjw5x1982_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232e12000ibyf573B90F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-05', '花园大床房', '大床房', '家庭亲子', 131, 0, 13, 8, '["客房服务","餐饮设施","整体满意度"]'::jsonb, '客房服务', '餐饮设施', '整体满意度'),
('68028542e3c98b0941766091', '酒店在市中心出行很方便门口就是地铁站。服务人员很热情友好。但是首日入住晚上准备睡觉时被床上用品卫生条件吓一跳有点怀疑清洁人员是否退房以后更换床上用品。发霉严重如果没有发现会影响身体健康。希望五星级酒店注重床品卫生
卫生：床品发霉', '["https://dimg04.c-ctrip.com/images/0231o12000i4hw77hAAE2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.2, 3, '2025-01-28', '花园双床房', '双床房', '家庭亲子', 114, 0, 11, 8, '["卫生状况","前台服务","交通便利性"]'::jsonb, '卫生状况', '前台服务', '交通便利性'),
('68028542e3c98b0941766092', '多年前就有去花园酒店住一住的想法，这次带着老的小的终于来了，虽然我们就生活在广州。可能还没到过年，酒店帮我把大床换成双床了，赞！去到办理入住，等了有一会，不过还是值得的。酒店环境不错，最惊喜的是她家的后花园，在寸土寸金的环市路，还有这一方天地，很棒！再说吃的这方面，感觉不达预期，特别是荔湾亭，出品和价格不成正比，只是盛名在外吧！', '["https://dimg04.c-ctrip.com/images/0236p12000ia5vlhlB322_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236h12000ia6mh5h915A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232712000ia7560l2FC2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.8, 4, '2025-02-03', '红棉大床套房', '套房', '家庭亲子', 165, 0, 14, 8, '["整体满意度","周边配套","性价比"]'::jsonb, '整体满意度', '周边配套', '性价比'),
('68028542e3c98b0941766094', '是我喜欢的酒店风格没错了。酒店的位置很好，就在沙面岛上，无论是欣赏珠江的风光还是探访充满风情的沙面建筑群都特别方便。值得表扬的还有吃白天鹅的早茶太方便啦，住酒店可以直接预约，不用排队。', '["https://dimg04.c-ctrip.com/images/0234g12000iarwfm64663_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232r12000iasiuq9BE06_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236t12000iarqqtw43BF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-04', '红棉大床套房', '套房', '家庭亲子', 92, 0, 4, 9, '["周边配套","整体满意度"]'::jsonb, '周边配套', '整体满意度', NULL),
('68028542e3c98b0941766095', '酒店房间宽敞设施完善，节日气氛浓厚。本来计划一天后去长隆玩住长隆附近，但是孩子们超级喜欢这里的瀑布和花园，早餐美食，又续住两天，游玩长隆后也要回来。下次来广州还住这??', '["https://dimg04.c-ctrip.com/images/0234712000iid111h121E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230112000iicpuqr68FD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231h12000iick06r8ACC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-13', '花园双床房', '双床房', '家庭亲子', 84, 0, 11, 7, '["整体满意度","餐饮设施","房间设施"]'::jsonb, '整体满意度', '餐饮设施', '房间设施'),
('68028542e3c98b0941766096', '服务满分，帮我两个房间都升级了套房，早餐也送了一份小朋友的。吃的很满意！那一层有个年轻阿姨打扫，房门出出进进都能遇到，打扫的很干净。花园又大又漂亮。', '["https://dimg04.c-ctrip.com/images/0230812000in5knr396C5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233s12000in5nal74656_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230h12000in53ayyF465_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230r12000in51ci46866_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-20', '花园双床房', '双床房', '家庭亲子', 74, 0, 23, 8, '["前台服务","客房服务","餐饮设施"]'::jsonb, '前台服务', '客房服务', '餐饮设施'),
('68028542e3c98b0941766097', '酒店过年装饰很有年味。有年会摆摊和舞狮活动。房间送的小食也很有年味喜庆。我们年夜饭也是在酒店瀑布餐厅享用单位。酒店整体还是有五星级酒店的标准的虽然房间有些小了。', '["https://dimg04.c-ctrip.com/images/0234612000i88v4exC20D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231m12000i88utk670C0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234u12000i88wjv5D0AB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2025-02-01', '花园双床房', '双床房', '家庭亲子', 80, 0, 11, 7, '["整体满意度","餐饮设施","客房服务"]'::jsonb, '整体满意度', '餐饮设施', '客房服务'),
('68028542e3c98b0941766098', '今天在花园酒店入住，一如既往的好评，今天特别的是Winnie 用心的服务，帮我妈妈用心解释。', '["https://dimg04.c-ctrip.com/images/0234412000jeflgm155C0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232n12000jeg0bvc2BDF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233y12000jeg5ind399C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-03-29', '花园大床房', '大床房', '家庭亲子', 46, 0, 4, 6, '["前台服务"]'::jsonb, '前台服务', NULL, NULL),
('68028542e3c98b0941766099', '每位酒店的工作人员都非常的热情，特别是rain让人感觉很舒服，环境也很赞，最主要的是干净卫生，这个价格入住这个酒店真的是超值，下次有机会一定会再来，停车方便，入住很快，房间也比较舒适，价格不贵，环境也不错，房间干净，入住首选，满意！', '["https://dimg04.c-ctrip.com/images/0235m12000jpfe81pC794_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230912000jpgxksg8D57_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233o12000jpgsuyh9EA7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234i12000jpfpv488869_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-04-10', '花园大床房', '大床房', '朋友出游', 116, 0, 1, 7, '["整体满意度","卫生状况","性价比"]'::jsonb, '整体满意度', '卫生状况', '性价比'),
('68028542e3c98b094176609a', '设施：很齐全，质量很好
卫生：很干净
环境：很豪华
服务：很到位特别热情，尤其是入住办理的美女Grihan女士服务特别满意??给个大赞', '["https://dimg04.c-ctrip.com/images/0235n12000io0lang3303_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233312000inzp89r3509_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233e12000inz5s05EA44_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-22', '花园大床房', '大床房', '商务出差', 67, 0, 10, 6, '["前台服务","整体满意度","卫生状况"]'::jsonb, '前台服务', '整体满意度', '卫生状况'),
('68028542e3c98b094176609b', '房间很好，整洁。去那里都很方便，交通便捷，对面就是广州酒家。服务很到位，好多个餐厅，吃饭很方便。各式的服务人员，各司其职，办理入住和退房，基本不用等等待。', '["https://dimg04.c-ctrip.com/images/0235012000i3ohjqdF122_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236b12000i3og49c1338_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236n12000i3ozui92CD7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232w12000i3ochej0BC1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230v12000i3o83920A0E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-01-27', '花园大床房', '大床房', '家庭亲子', 77, 0, 5, 7, '["交通便利性","周边配套","退房/入住效率"]'::jsonb, '交通便利性', '周边配套', '退房/入住效率')
 ON CONFLICT (_id) DO NOTHING;
